    {
        "control_id": "DATA_001",
        "control_name": "Information access restriction",
        "vodafone_standard": "",
        "domain": "Data",
        "d_statements": [
            {"id": "D1", "text": "An access control model based on system roles / profiles with restricted permissions has been defined, approved, documented and consistently configured on live systems to provide different users with the capabilities to access information and perform transactions on a need to know / do basis."},
            {"id": "D2", "text": "Changes of the access control model require a formal approval."},
            {"id": "D3", "text": "The access control model is being reviewed on a regular basis and updated as required."},
            {"id": "D4", "text": "The provisioning of user access is based on the access control model."},
            {"id": "D5", "text": "The system fully supports the access control model by restricting the users access to data / transactions according to defined role / profile."},
            {"id": "D6", "text": "The access control model and its implementation restrict administrative capabilities including creation / amendment / revocation of access and changing of security relevant system parameters to specific administrator roles / profiles."},
        ],
        "e_statements": [
            {"id": "E1", "text": "Approved document describing the access control model. Report with roles / profiles configured in the system and confirmation that these are aligned with the documented model."},
            {"id": "E2", "text": "Evidence of latest change to the model, corresponding management approval and supporting change management process where applicable."},
            {"id": "E3", "text": "Evidence of last review of the model and sign-off of the revised document."},
            {"id": "E4", "text": "Copy of access request form or report from access management system demonstrating that the roles / profiles which can be requested do match with the model."},
            {"id": "E5", "text": "Screenshot showing for one role / profile with restricted access that the system enforces the restriction (e.g. error message when trying to execute a restricted functionality or comparison of available menu options with a different role / profile with higher privileges."},
            {"id": "E6", "text": "Screenshot showing for one role / profile with non administrative access that administrative functions, e.g. creation / amendment / revocation of access, changing of security relevant system parameters aren't available / can't be successfully executed."},
        ],
    },
    {
        "control_id": "GENERAL_001",
        "control_name": "Secure log-on procedures",
        "vodafone_standard": "",
        "domain": "General",
        "d_statements": [
            {"id": "D1", "text": "Passwords aren't displayed while being entered and aren't transmitted in clear text over a network."},
            {"id": "D2", "text": "Log-on information (username and password) is being validated only on completion of all input data - if an error condition arises, the system doesn't indicate which part of the data is correct or incorrect."},
            {"id": "D3", "text": "Accounts are being locked or blocked for a period of time after 10 consecutive unsuccessful log-on attempts."},
            {"id": "D4", "text": "Unsuccessful and successful attempts are being logged and authentication and administrative events are fed into a SIEM solution in line with the T2 Logging and Monitoring Global Standard v2.31 or higher."},
            {"id": "D5", "text": "Inactive sessions are being terminated or locked after a defined period of inactivity."},
        ],
        "e_statements": [
            {"id": "E1", "text": "Screenshot taken during authentication which demonstrates that password is masked during entry; confirmation that passwords are not transmitted in clear text over the network when logging on (e.g. use of https)."},
            {"id": "E2", "text": "Screenshots taken with incorrect username entered. Screen shot taken with incorrect password entered. Screen shot taken with incorrect username and password entered. Alternativly, screen shot showing error message configuration."},
            {"id": "E3", "text": "Screenshot taken after a number of failed logon attempts which demonstrates that the account is locked or logon is temporarily blocked. Screenshot or report showing the system setting configuration."},
            {"id": "E4", "text": "Log files from the system showing the unsuccessful logon attempts and screenshot of the resulting security event.  Confirmation from (C)SOC that they are receiving authentication logs."},
            {"id": "E5", "text": "Screenshot showing terminated or locked session after a period of inactivity. Screenshot or report showing the system setting configuration. Copy of policy showing the time out requirements for periods of inactivity."},
        ],
    },
    {
        "control_id": "IAM_008",
        "control_name": "Customer authentication",
        "vodafone_standard": "Strong Authentication Solutions (formally - Multi Factor Authentication (MFA)) [CYBER/STD/039] Cust_Auth_MR1",
        "domain": "IAM",
        "d_statements": [
            {"id": "D1", "text": "All attempted access to high risk transactional or sensitive data (as defined in the Tier 2 Access & Authentication Detailed Requirements), must be authenticated by a combination of at least two (MFA) authentication factors with one factor meeting the requirements of a standard strong authentication (as defined in the Tier 3 standard Strong Authentication Solutions)."},
            {"id": "D2", "text": "Backup authentication factors must offer a level of security which is equivalent to the default MFA authentication factor, e.g., an additional authentication factor to be collected from customer for back up purposes.​"},
            {"id": "D3", "text": "For the recovery of accounts, customer must be strongly authenticated before re-enabling account access and activating a new MFA factor."},
            {"id": "D4", "text": "Passwords aren't displayed while being entered and aren't transmitted in clear text over a network."},
            {"id": "D5", "text": "Log-on information (username and password) is being validated only on completion of all input data - if an error condition arises, the system doesn't indicate which part of the data is correct or incorrect."},
            {"id": "D6", "text": "Accounts are being locked or blocked for a period of time after 5 consecutive unsuccessful log-on attempts."},
            {"id": "D7", "text": "Inactive sessions are being terminated or locked after a defined period of inactivity."},
        ],
        "e_statements": [
            {"id": "E1", "text": "Evidence showing the configuration of MFA, including the type of MFA configured. Screens shots of the process in place or logs showing the MFA authentication occuring."},
            {"id": "E2", "text": "Screenshots showing back up authentication methods enabled."},
            {"id": "E3", "text": "Documented recovery process for customer accounts including authentication steps. Evidence that systems have this process technically enforced."},
            {"id": "E4", "text": "Screenshot taken during authentication which demonstrates that password is masked during entry; confirmation that passwords are not transmitted in clear text over the network when logging on (e.g., use of https)."},
            {"id": "E5", "text": "Screenshots taken with incorrect username entered. Screen shot taken with incorrect password entered. Screen shot taken with incorrect username and password entered. Alternativly, screen shot showing error message configuration."},
            {"id": "E6", "text": "Configuration showing account lock or block settings. Logs showing an account is locked after 5 unsuccessful attempts."},
            {"id": "E7", "text": "Configuration showing account inactivity settings."},
        ],
    },
    {
        "control_id": "IAM_009",
        "control_name": "Multi-factor authentication",
        "vodafone_standard": "Strong Authentication Solutions (formally - Multi Factor Authentication (MFA)) [CYBER/STD/039] [MR3]",
        "domain": "IAM",
        "d_statements": [
            {"id": "D1", "text": "Remote access and privileged access to systems is protected by multi-factor authentication with allowed knowledge, possession and inherent factors meeting the requirements for creation, transmission, enrolment, storage and 1:1 mapping to individual users (multiple people can’t share MFA authenticators) in line with the T3 standard Strong Authentication Solutions. One of the factors used must meet the requirements of an enhanced strong authentication."},
            {"id": "D2", "text": "MFA technologies and authenticators use strong cryptographic algorithms and key lengths to generate and store key/tokens, and authentication data in transit is protected using encrypted protocols in line with the Tier 3 Cryptography v1.0 or higher."},
            {"id": "D3", "text": "A process is in place to suspend/disable authenticators immediately after being reported by the user as lost/stolen/duplicated or suspected of being compromised."},
            {"id": "D4", "text": "MFA must be applied to any processes supporting the MFA solution including   - user self-service processes;   - enrolment processes;   - credential management processes;   - processes covering lost or stolen authenticators; and  - service desk processes (including bots)."},
            {"id": "D5", "text": "Where a physical token is registered to a user, dormant tokens must be disabled after 90 days of inactivity."},
            {"id": "D6", "text": "Authentication and administrative events including unsuccessful and successful attempts are being logged."},
        ],
        "e_statements": [
            {"id": "E1", "text": "MFA solution documentation – LMs & GEs must track and evidence coverage. Evidence from the MFA solution showing 1:1 mapping for authenticators:users. Evidence that OTPs cannot be shared."},
            {"id": "E2", "text": "Screenshots showing the MFA technology in use uses strong cryptographic algorithms and key lengths to generate and store keys/tokens. MFA solution documentation."},
            {"id": "E3", "text": "Evidence that information is available to inform users about the reporting process for lost/stolen authenticators. A copy of the process document to suspend/disable authenticators. Evidence of the process in effect."},
            {"id": "E4", "text": "MFA process documentation showing how and when users will be challenged when managing their MFA or evidence of configuration. Evidence showing the process in effect."},
            {"id": "E5", "text": "Evidence showing authenticator last use date for active authenticators as well as evidence of disabled authenticators with their last use date and disablement date."},
            {"id": "E6", "text": "Log files from the system showing the unsuccessful logon attempts and screenshot of the resulting security event."},
        ],
    },
