    {
        "control_id": "ENDPOINT_005",
        "control_name": "Anti-malware tools",
        "vodafone_standard": "Tier 2 Secure System Management & Protection (CYBER_038) Section 5.5 Anti-Malware and Endpoint Detection & Response (EDR)",
        "domain": "Endpoint",
        "d_statements": [
            {"id": "D1", "text": "Real time anti-malware protection is enabled and configured in line with policy."},
            {"id": "D2", "text": "A scan of the organisation’s systems is being enforced at least weekly covering the memory, boot sector, registry and files stored on local drives, including archives."},
            {"id": "D3", "text": "All portable storage media connected to the organisation’s clients and servers are being scanned for malware."},
            {"id": "D4", "text": "Browser based protection against malicious scripts executed on endpoints are used, especially to filter against known sites with security issues."},
            {"id": "D6", "text": "Real time anti-malware is enabled on the standard build or OS image for all new systems and on all supported clients and server operating systems (Windows, MacOS and Linux), including all physical and virtual devices hosted on premise or within public cloud based IaaS environments."},
            {"id": "D7", "text": "Where anti-malware protection on servers and endpoints is being temporarily disabled by administrators this has been formally authorised based on a specific business need and the period is being kept to a minimum to perform the required tasks."},
            {"id": "D8", "text": "Users other than administrators aren’t able to disable or otherwise modify anti-malware protection on servers and endpoints."},
            {"id": "D9", "text": "Mechanisms are in place to monitor all systems and devices to detect inactive anti-malware protection."},
            {"id": "D10", "text": "Processes are in place to re-enable anti-malware protection on systems where it has been found to be inactive without formal authorisation in a timely manner."},
            {"id": "D11", "text": "Malware signatures for all anti-malware tools are being monitored on a regular basis."},
            {"id": "D12", "text": "Outdated signatures and software found are updated in a timely manner (within 2 days for servers and within 14 days for clients)."},
            {"id": "D13", "text": "Exclusions from real-time and scheduled anti-malware scanning have the risk documented and risk accepted."},
        ],
        "e_statements": [
            {"id": "E1", "text": "Local Market/Entity: Evidence showing that systems have real time anti-malware protection enabled."},
            {"id": "E2", "text": "- Central: Configuration showing that weekly scans are being enforced for clients and at least monthly for servers.   - Central: Examples of any alerts generated if scans fail to run."},
            {"id": "E3", "text": "Central: Configuration and/or logs showing that malware scans are enforced when removable media is connected to corporate clients and servers."},
            {"id": "E4", "text": "Central: Evidence that the platform is configured in line with the baseline standard including the coverage of browser based malicious scripts or sites with security issues."},
            {"id": "E5", "text": "- Local Market/Entity: Evidence of investigation, corrective actions taken and resolution timelines.  * - Local Market/Entity: Evidence that they been captured and monitored locally."},
            {"id": "E6", "text": "Local Market/Entity: Base image or configuration scripts for servers and workstations. showing that anti-malware is installed and updated by default when new systems are deployed."},
            {"id": "E7", "text": "- Central: List of email servers and endpoints with AM disabled per entity.  - Local Market/Entity: Evidence of formal approval in place for temporarily disabling anti-malware protection on servers and endpoints."},
            {"id": "E8", "text": "Central: Evidence of configuration setting showing that non-admin users can't disable or amend anti-malware settings on a server or on endpoints."},
            {"id": "E9", "text": "Central: Evidence of the anti-malware tool console demonstrating that all servers and devices in scope are reporting their anti-malware protection status (active or inactive), where a system is found to be inactive, an alert is raised on the console."},
            {"id": "E10", "text": "Local Market/Entity: For any system found inactive without formal authorisation, evidence showing that anti-malware protection is re-enabled in a timely manner​ e.g. screenshot of one affected system with anti-malware protection re-enabled OR support ticket to re-enable anti-malware protection."},
            {"id": "E11", "text": "Central: Evidence of configuration settings showing that malware signatures are updated at defined intervals."},
            {"id": "E12", "text": "Central: Where"},
            {"id": "E13", "text": "Local Market/Entity: Report of endpoints which cannot have AV tooling implemented and supporting risk assessments."},
        ],
    },
