    {
        "control_id": "ENDPOINT_007",
        "control_name": "Endpoint detection and response (EDR)",
        "vodafone_standard": "",
        "domain": "Endpoint",
        "d_statements": [
            {"id": "D1", "text": "EDR tooling is included as part of gold build standards or standard new build processes."},
            {"id": "D2", "text": "EDR tools must be enabled, active (communicating events to central console) and up to date on clients and servers. If disabled, EDR must be re-enabled as soon as possible."},
            {"id": "D3", "text": "EDR tools must:  - contain an extensive and comprehensive set of high quality out of the box detection rules mapped to the MITRE ATT&CK framework;  - perform automatic real time system event monitoring;  - ingest external threat intelligence and customised threat indicators;  - trigger alerts;  - enable remote endpoint response capabilities to investigate, contain and remediate incidents;  - capture and store system events online for a minimum of 30 days and provide a hunting capability; and  - acquire artifacts and any associated files for analysis.  The configuration must be protected from unauthorised changes or disablement."},
            {"id": "D4", "text": "EDR rules must be reviewed and improved continually in line with the latest incidents and threat intelligence."},
            {"id": "D5", "text": "Exceptions are reviewed on a regular basis, at least annually."},
            {"id": "D6", "text": "Processes must exist and be followed to respond to and remediate alerts. High priority alerts should be triaged and responded to within 90 minutes once received by the SOC."},
            {"id": "D7", "text": "For any endpoint that cannot have tooling implemented appropriate alternative controls should be implemented based on risk."},
        ],
        "e_statements": [
            {"id": "E1", "text": "[Local] Evidence of gold builds/new build process that includes EDR at the current acceptable version."},
            {"id": "E2", "text": "[Central] Reports from EDR console showing EDR status for endpoints including confirmation that EDR is active and up to date. Evidence of alerting configuration if EDR is disabled as well as evidence showing it is re-enabled within the required time (2 calendar days for servers and 14 calendar days for endpoints).   [Local] Report from asset management confirming the number of endpoints and servers to be covered. Note: Local support may be required for remediation activities even if evidence is provided centrally."},
            {"id": "E3", "text": "[Central] Evidence showing the configuration of EDR is inline with the Secure System Management and Protection Global Standard and cannot be disabled or changed without appropriate authorisation."},
            {"id": "E4", "text": "[Central] Evidence from incidents and threat intel that has led to custom rules being configured and deployed."},
            {"id": "E5", "text": "[Central] Evidence of all exceptions that have been granted and supporting evidence showing their last review.  [Local] Local exception management process."},
            {"id": "E6", "text": "[Central] Copy of process document. Evidence of alerts being passed to SOC, triaging of alerts and passing relevant alerts to local teams where necessary.  [Local] Copy of process document. Evidence of alerts passed from central teams to market/entity along with response and remediation activities carried out relating to alerts."},
        ],
    },
