    {
        "control_id": "ENDPOINT_008",
        "control_name": "Voicemail Service and Interactive Voice Response (IVR) Service security",
        "vodafone_standard": "",
        "domain": "Endpoint",
        "d_statements": [
            {"id": "D1", "text": "Authentication mechanisms to obtain access to Voicemail systems are configured and supported by PIN management processes and systems in line with requirements MR1 to MR7, MR9, MR11, MR12 and MR16 as defined in the Tier 3 for Voicemail and Interactive Voice Response v2.0 or higher."},
            {"id": "D2", "text": "Greeting messages, voicemails and voicemail PINs stored on Voicemail infrastructure are protected against unauthorised access or modification and the protection prevents operations staff from accessing greeting messages, voicemails or voicemail PINs in plaintext form."},
            {"id": "D3", "text": "Processes and mechanisms for authenticating customers contacting customer care centres and restricting sensitive information which can be provided to the customer related to the customer’s mailbox have been put in place and are supported by customer care agent training in line with requirements MR11, MR21 to MR26 as defined in the Tier 3 for Voicemailand Interacive Voice Response v2.0 or higher."},
            {"id": "D4", "text": "Voicemail systems are configured to restrict call back functionality in line with requirements MR13 and MR14 as defined in the Tier 3 for Voicemail and Interactive Voice Response v2.0 or higher."},
            {"id": "D5", "text": "Effective change control processes are in place to ensure that security relevant configurations remain in place following operational changes."},
            {"id": "D6", "text": "Access to visual voicemail over WiFi and cellular networks is protected by TLS."},
        ],
        "e_statements": [
            {"id": "E1", "text": "Screenshots from the system demonstrating that the system configuration complies with the relevant requirements."},
            {"id": "E2", "text": "Confirmation that showing that greeting messages, voicemails and PINs are appropriately protected from unauthorised access, e.g. system documentation or written confirmation from supplier."},
            {"id": "E3", "text": "Copy of procedures supporting the relevant requirements and evidence that customer care agents are trained accordingly (e.g. content used for training and date of last training, user attendance record)."},
            {"id": "E4", "text": "Screenshots from the system demonstrating that the system configuration complies with the relevant requirements."},
            {"id": "E5", "text": "Copy of applicable documented change process. Example of a documented and appropriately authorised change in line with the defined process. Documentation of mechanisms, procedures which ensure continuous compliance of systems with security requirements. Evidence that these have been implemented."},
            {"id": "E6", "text": "Screenshots from the system demonstrating that the system configuration complies with the relevant requirements."},
        ],
    },
    {
        "control_id": "NETWORK_007",
        "control_name": "Segregation in networks",
        "vodafone_standard": "",
        "domain": "Network",
        "d_statements": [
            {"id": "D1", "text": "A Security Zoning Model for the organisation's networks which segregates groups of information services, users and information systems to enforce the principle of least privilege has been defined, documented and communicated to key stakeholders."},
            {"id": "D2", "text": "Whenever the micro-segmentation or application segmentation model is applied, every workload has to be allocated to a zone as per section 4. Flows between workloads must comply with the micro-segmentation models illustrated in section 2.2.  Whenever the VLAN zoning model is applied, zones should be defined as a minimum according to the model described in section 4 of the Network Security Micro-Segmentation standard. Flows between zones must comply with requirements MR24 - MR31 as a minimum."},
            {"id": "D3", "text": "The access between security zones is controlled / restricted by physical separation of networks or via gateways."},
            {"id": "D4", "text": "Where legacy systems / networks don't comply with the Security Zoning Model, a risk assessment is being performed and appropriate alternative measures are being taken, e.g. uplift / migration / retirement, implementation of compensating controls and / or risk acceptance."},
            {"id": "D5", "text": "All existing zones are accurately described, documented and tracked in a firewall policy management solution."},
            {"id": "D6", "text": "Processes are in place to ensure that new systems are designed and deployed to comply with the Security Zoning Model."},
        ],
        "e_statements": [
            {"id": "E1", "text": "Documents or diagrams of the organisation's network security zones, demonstrating that information services, users and information systems are classified and segregated using the principle of least privilege according to specific functions (e.g. presentation, application, database, management, infrastructure services) and deployment status (development, test, production). Evidence the Security Zoning Model is reviewed and approved by management, and made available to key stakeholders."},
            {"id": "E2", "text": "Documented confirmation that the evidence supplied in"},
            {"id": "E3", "text": "Screenshots of firewall rules or IP whitelists demonstrating restriction of access between security zones as defined in"},
            {"id": "E4", "text": "Excerpt of risk register demonstrating that risk assessments are performed, and appropriate controls are implemented or planned, when networks don't comply with the Security Zoning Model (e.g. evidence examined in [E1-E3] show discrepancies between policy and implementation). Change tickets demonstrating the implementation of compensating controls."},
            {"id": "E5", "text": "Screenshot of firewall policy management solution listing all existing zones, their functions, and traffic permitted to access the zones."},
            {"id": "E6", "text": "Copy of design document for a new or upgraded system demonstrating that the network requirements comply with the Security Zoning Model, evidence of sign-off on the design by persons responsible i.e. security prior to development and project go-live, documented risk assessments and plan correction or compensating controls where the new systems do not comply with the Security Zoning Model."},
        ],
    },
    {
        "control_id": "DATA_002",
        "control_name": "Protection of information in transit",
        "vodafone_standard": "Tier 3 LAN Authentication (CYBER/STD/062)",
        "domain": "Data",
        "d_statements": [
            {"id": "D1", "text": "Secure encryption mechanisms in line with requirements defined in   - CYBER/STD/042 Radio Access Security v1.1 or higher  have been configured and activated to protect the integrity and confidentiality of the customer's GSM, GPRS, UMTS, LTE and public WiFi traffic."},
            {"id": "D2", "text": "Access to the organisation's sensitive information transmitted over the organisation's LAN infrastructure is being protected in line with requirements defined in the Tier 3 LAN Authentication (CYBER/STD/062) version 1.0 or higher."},
            {"id": "D3", "text": "Access to the organisation's sensitive information transmitted over the organisation's WiFi infrastructure is being protected through secure protocols and strong encryption."},
            {"id": "D4", "text": "Access to the organisation's sensitive information transmitted over Wide Area Networks is being protected through physical access controls covering transmission lines and equipment and / or secure protocols and strong encryption."},
            {"id": "D5", "text": "Contracts and Non-Disclosure Agreements (NDA) with external parties define the secure transfer of business information between the organisation and external parties."},
            {"id": "D6", "text": "The organisation's information classification scheme has been communicated to external parties and sensitive information sent to external parties is clearly marked as such."},
            {"id": "D7", "text": "Encryption or information rights management tools are available in the office environment in conjunction with guidance on how to use them in order to enable users to protect individual communication of sensitive information with external parties."},
            {"id": "D8", "text": "Where sensitive information is being exchanged, connections between the organisation's systems and systems of external parties are secured through strong cryptographic mechanisms which comply with the organisation's policies."},
            {"id": "D9", "text": "Where the organisation's applications pass sensitive information over public networks these have been assessed prior to use / go live to identify security measures e.g. the use of secure protocols and cryptographic mechanisms to protect the confidentiality and integrity of the information. The assessments consider specific risks such as fraudulent activities, contract dispute and unauthorised disclosure or modification."},
            {"id": "D10", "text": "Required security measures and controls identified during the risk assessment have been documented and backed up by an action plan to close gaps in a timely manner as required."},
            {"id": "D11", "text": "Strong authentication and encryption methods are used which comply with the organisation's policies."},
            {"id": "D12", "text": "The applications and the defined security measures have been thoroughly tested against the requirements and robustness against external and insider attacks and weaknesses found are addressed through risk assessments and remediation activities."},
            {"id": "D13", "text": "A formal acceptance process is being followed which covers security aspects prior to applications going live."},
            {"id": "D14", "text": "Assessments are being reviewed and security requirements are being updated as required in case of significant changes in the information handling and if new threats become visible."},
            {"id": "D15", "text": "Digital signatures are used by each party in all transactions and all communication is encrypted; i.e. plain text must be transformed into unreadable cipher text."},
            {"id": "D16", "text": "Secure communications protocols must be used as applicable, e.g. TLS, IPsec, S/MIME, HTTPS."},
            {"id": "D17", "text": "Transaction details aren’t stored on any medium that is directly accessible form the Internet or, where this can’t be avoided, these are protected by strong encryption."},
        ],
        "e_statements": [
            {"id": "E1", "text": "Screenshots from network elements, network element managers or other network components demonstrating that encryption mechanisms are configured in line with relevant requirements for GSM, GPRS, UMTS, LTE and public WiFi."},
            {"id": "E2", "text": "Screenshots from network elements, network element managers or other network components demonstrating that the system configuration complies with the relevant requirements."},
            {"id": "E3", "text": "Screenshots from network elements, network element managers or other network components demonstrating that the system configuration complies with the relevant requirements."},
            {"id": "E4", "text": "Screenshots from network elements, network element managers or other network components demonstrating that secure encryption protocols are enabled, and documentation of physical access controls for equipment e.g. restricted access and protection from tampering."},
            {"id": "E5", "text": "Copy of contract and NDA with an external party with access to Vodafone business information and systems."},
            {"id": "E6", "text": "Documented acceptance of Vodafone's information classification scheme by external parties, e.g. via contract or NDA or equivalent. Example of sensitive document sent to external parties clearly marked with appropriate classification labels."},
            {"id": "E7", "text": "Documentation or screenshot of information rights management and data encryption tools available in the office environment. Documentation of guidance on how and when to use these tools for protecting individual communication with external parties in line with information classification policy."},
            {"id": "E8", "text": "Screenshot demonstrating cryptographic mechanisms are configured on connections or edge devices between the organisation's and external systems used for exchanging sensitive information."},
            {"id": "E9", "text": "Policy or process document for conducting security assessments of applications which pass sensitive information over public networks. Documented risk assessments considering specific risks for the sampled networks including fraud, contract dispute, and unauthorised misuse of information."},
            {"id": "E10", "text": "Documented mitigating controls, risk acceptance, or follow-up action plan as a result of risk assessment provided in"},
            {"id": "E11", "text": "Policy documentation specifying adequate authentication and encryption methods. Screenshot demonstrating authentication methods are enabled according to the organisation's policies for relevant systems used to exchange sensitive information to external parties."},
            {"id": "E12", "text": "Reports of network and application penetration tests or security audits. Documented risk assessment for weaknesses found, including mitigating controls and remediation activities."},
            {"id": "E13", "text": "Policy documentation specifying the formal risk acceptance process prior to applications going live. Documented acceptance of risks identified in [E9, E12]."},
            {"id": "E14", "text": "Evidence that documented risk assessment is being reviewed and updated e.g. revision history. Security policies and requirements documents are updated with new threats identified from risk assessments."},
            {"id": "E15", "text": "Screenshot demonstrating digital signatures are used in all information exchange transactions e.g. emails, documents containing sensitive information. Screenshot of application logs demonstrating that sensitive information is not transmitted in plain text OR screenshot demonstrating attempt to access encrypted information without proper authorisation returns cipher text."},
            {"id": "E16", "text": "Screenshots from network elements, network element managers or other network components demonstrating that communications protocols are configured in line with relevant policy requirements."},
            {"id": "E17", "text": "Screenshot demonstrating database or storage system for transaction details is segregated from direct internet access e.g. using a firewall or proxy or network segmentation."},
        ],
    },
    {
        "control_id": "DATA_003",
        "control_name": "Email Data Loss Prevention",
        "vodafone_standard": "",
        "domain": "Data",
        "d_statements": [
            {"id": "D1", "text": "The selected DLP tool covers all users and all email gateways."},
            {"id": "D2", "text": "A DLP document is in place and data identification patterns and enforcement rules have been defined by the DLP Authority and DLP Configuration Group (Information Classification and Protection Global Standard); the document is updated as required following a formal process which includes approvals from the relevant stakeholders."},
            {"id": "D3", "text": "Data identification patterns have been defined by the DLP Authority and DLP Configuration Group based on regular expressions and / or indexed data which allow detecting all sensitive data with a high probability."},
            {"id": "D4", "text": "Data identification patterns and enforcement rules have been thoroughly tested and implemented as per the requirements from the DLP Authority and DLP Configuration Group."},
            {"id": "D5", "text": "On-prem solutions only: Mechanisms are in place to ensure that all 'DLP control points/agent' receive software and ruleset updates and send event data including monitoring and follow-up of unresponsive components."},
            {"id": "D6", "text": "A process is in place to review all DLP events received from the email DLP tooling; all events which haven't been confirmed to be false-positives are followed-up in a timely manner with appropriate actions, escalation processes and defined consequence management (communication, awareness, disciplinary process, link into incident response process)."},
            {"id": "D7", "text": "The DLP tool operates in blocking mode and / or encryption of sensitive data leaving the endpoint is enforced."},
            {"id": "D8", "text": "The status of DLP events is being documented including resolution cases and actions taken.​"},
            {"id": "D9", "text": "Potentially sensitive evidence captured by the DLP tools is protected and access to the DLP tools is tightly restricted to mitigate the risk that this data leaks out of the organisation from the tool.​"},
            {"id": "D10", "text": "A process is in place to identify trends and to respond as required. Reporting is available including to support the process including volumes of alerts, volumes of key alerts, status of alerts per market, global investigations outcome and risk mitigation per market as per the Information Classification and Protection Global Standard. ​"},
        ],
        "e_statements": [
            {"id": "E1", "text": "Up-to-date architecture diagram which shows DLP control points deployed close to the gateways and screenshot from the DLP tool console demonstrating coverage of all users and gateways in scope (i.e., all control points are online)."},
            {"id": "E2", "text": "Copy of Data Loss Prevention Guidance Document which identifies data identification patterns and enforcement rules for data in motion, in use, and at rest. Evidence that the document is reviewed and updated as required and has been made available for key stakeholders. This can include policies for handling C3/ C4 information, MSISDNs, credit card details, etc."},
            {"id": "E3", "text": "Documentation or screenshot from the DLP tool detailing data identification patterns which allows detecting loss or unauthorised disclosure of sensitive data. Screenshot of logs generated, or alerts received when events of interest occur."},
            {"id": "E4", "text": "Evidence that the data identification rules have been tested before being implemented on production environments, e.g., testing reports, screenshots of change tickets, or email correspondence.​"},
            {"id": "E5", "text": "Screenshot from DLP administration tool demonstrating that software and policy updates are enabled on all DLP control points, and unresponsive components are monitored, with appropriate follow-up. ​  OR screenshots from DLP control points demonstrating that software and policy updates are enabled, and error logs for unresponsive components are sent to a centralised monitoring tool.​"},
            {"id": "E6", "text": "Process documentation for reviewing DLP events. Screenshot of DLP logs demonstrating that all confirmed events are reviewed OR logs demonstrating that there are no unprocessed events exceeding SLA. Where applicable, provide screenshots or documents of follow-up measures e.g., incident response and resolution, awareness and communication materials. Evidence of escalation processes and consequence matrix.​"},
            {"id": "E7", "text": "Screenshot from DLP administration tool demonstrating that all mandatory policies are implemented, and blocking mode or pop-up notifications are in place for high severity alerts, with encryption enforced on sensitive information leaving the endpoint. ​"},
            {"id": "E8", "text": "Screenshots from DLP administration tool demonstrating the process of reviewing, categorising and closing DLP events. Where an event is categorised as an incident, screenshots or documentation demonstrating investigation into the incident, including actions taken, escalation and resolution."},
            {"id": "E9", "text": "Screenshot of directory for users permitted to access the DLP tool, select a user and obtain formal access request ticket or email approval for the sampled user. Screenshot demonstrating that sensitive information captured in the DLP is masked in the GUI and in reports."},
            {"id": "E10", "text": "Report, meeting minutes or screenshots demonstrating identification and review of DLP trends by management, e.g., tracking performance against KPIs, policy violations and suggestions for improvement. Where applicable, support tickets or email correspondence demonstrating actions taken resulting from management review of DLP trends."},
        ],
    },
    {
        "control_id": "ENDPOINT_009",
        "control_name": "Email security",
        "vodafone_standard": "Tier 3 Email Hygiene (CYBER/STD/027) MR1 to MR3",
        "domain": "Endpoint",
        "d_statements": [
            {"id": "D1", "text": "Email messaging systems comply with the mandatory requirements relating to the blocking and filtering of malicious emails (MR1, MR2, MR3) as defined in the in the Tier 3 Email Hygiene v2.0 or higher.​"},
            {"id": "D2", "text": "Email messaging systems comply with mandatory requirement relating to the handling of email floods and overload situations in case of DDOS attacks (MR4) as defined in the in the Tier 3 Email Hygiene v2.0 or higher.​"},
            {"id": "D3", "text": "Email messaging systems comply with mandatory requirement relating to the integrity of email communication flows (MR5) as defined in the in the Tier 3 Email Hygiene v2.0 or higher.​"},
            {"id": "D4", "text": "Email messaging systems comply with mandatory requirement relating to the processing of email messages and the storage of meta-data for search capabilities (MR6) as defined in the in the Tier 3 Email Hygiene v2.0 or higher.​"},
            {"id": "D5", "text": "Email messaging systems comply with mandatory requirements relating to the inbound authentication checks of email senders and the validation of email recipients (MR7, MR8) as defined in the in the Tier 3 Email Hygiene v2.0 or higher.​"},
            {"id": "D6", "text": "Email messaging systems comply with mandatory requirement relating to the blocking of emails from malicious senders and permitting approved senders (MR9) as defined in the in the Tier 3 Email Hygiene v2.0 or higher.​"},
            {"id": "D7", "text": "Email messaging systems comply with mandatory requirement relating to the marking of external emails as such (MR10) as defined in the in the Tier 3 Email Hygiene v2.0 or higher.​"},
            {"id": "D8", "text": "Email messaging systems comply with mandatory requirements to search and delete malicious emails after they have been delivered (MR11), detect user or domain-based impersonations (MR12) and scanning of attachments (MR13) and web URLs (MR14) as defined in the in the Tier 3 Email Hygiene version 2.0 or higher​."},
            {"id": "D9", "text": "Email messaging systems comply with mandatory requirements (MR1 - MR5) in the Tier 3 Trusted Messaging v2.0 or higher."},
            {"id": "D10", "text": "Email messaging systems support email sender authentication techniques, SPF (MR1, MR2), DKIM (MR3, MR4) where implemented and DMARC (MR5, MR6), to comply with mandatory requirements as defined in the in the Tier 3 Email Sender Authentication v2.03 or higher.​"},
        ],
        "e_statements": [
            {"id": "E1", "text": "Screenshots or reports from the system demonstrating that the email messaging system complies with the relevant mandatory requirements relating to the blocking and filtering of malicious emails."},
            {"id": "E2", "text": "Screenshots or reports from the system demonstrating that the email messaging system complies with the relevant mandatory requirements relating to the handling of email floods and overload situations in case of DDOS attacks."},
            {"id": "E4", "text": "Screenshots or reports from the system demonstrating that the email messaging system complies with the relevant mandatory requirements relating to the processing of email messages and store of meta-data for search capabilities."},
            {"id": "E5", "text": "Screenshots or reports from the system demonstrating that the email messaging system complies with the relevant mandatory requirements relating to the inbound authentication checks of email senders and the validation of email recipients."},
            {"id": "E6", "text": "Screenshots or reports from the system demonstrating that the system complies with the relevant mandatory requirements relating to the blocking of emails from malicious senders and permitting approved senders."},
            {"id": "E7", "text": "Screenshots or reports from the system demonstrating that the email messaging system complies with the relevant mandatory requirements relating to the marketing of external emails.  Examples of external emails received, showing that the recipient is visually alerted."},
            {"id": "E8", "text": "Screenshot of the feature config or reports of deleted malicious messages. If it is not automated, then drafted process would be required. For MR12 to MR14 screenshot or report demonstrating the relevant mandatory requirement."},
            {"id": "E9", "text": "Screenshots or reports from the system demonstrating that the system complies with the relevant mandatory requirements."},
            {"id": "E10", "text": "Screenshots or reports from the system demonstrating that the system has been designed to deliver email sender authentication techniques, SPF, DKIM and DMARC and complies with the relevant mandatory requirements defined in the Email Sender Authentication Standard."},
        ],
    },
